sysauto_script.script:
// Find all expired TTL resources
var ttlGr = new GlideRecord('x_146833_idpkiro_u_idp_ttl_resource');
ttlGr.addQuery('status', 'active');
ttlGr.addQuery('expires_at', '<=', new GlideDateTime());
ttlGr.query();

var expiredCount = 0;

while (ttlGr.next()) {
    try {
        // Execute cleanup script for the resource
        var execution = new GlideRecord('x_146833_idpkiro_u_idp_action_execution');
        if (execution.get(ttlGr.execution.toString())) {
            var cleanupScript = execution.action_form.cleanup_script.toString();
            if (cleanupScript) {
                var cleanup = new Function('resourceId', 'resourceType', 'gs', cleanupScript);
                cleanup(ttlGr.resource_id.toString(), ttlGr.resource_type.toString(), gs);
            }
        }

        // Update TTL record
        ttlGr.setValue('status', 'expired');
        ttlGr.setValue('expired_on', new GlideDateTime());
        ttlGr.update();

        // Update execution record
        execution.setValue('status', 'expired');
        execution.setValue('completed_on', new GlideDateTime());
        execution.update();

        expiredCount++;
        gs.info('IDP TTL: Expired resource ' + ttlGr.resource_id.toString());

    } catch (e) {
        gs.error('IDP TTL cleanup failed for ' + ttlGr.resource_id.toString() + ': ' + e.message);
        ttlGr.setValue('status', 'cleanup_failed');
        ttlGr.setValue('error_message', e.message);
        ttlGr.update();
    }
}

if (expiredCount > 0) {
    gs.info('IDP TTL Cleanup: Expired ' + expiredCount + ' resources');
}
